let oldPostId = '';
let m = permalink.match(/facebook\.com\/(\d+)\/posts\/(\w+)/);
if (m) { oldPostId = `${m[1]}_${m[2]}`; }
else { m = permalink.match(/facebook\.com\/(\d+_\w+)/); if (m) oldPostId = m[1]; }
return [{ json: {
  notionPageId: rows[0].id,
  contract_no: txt('жЎҲд»¶з·Ёиҷҹ').toUpperCase(),
  keisId: p['KEISзү©д»¶ID']?.number || null,
  oldPermalink: permalink,
  oldPostId,
  йҮҚзҷјж¬Ўж•ё: p['йҮҚзҷјж¬Ўж•ё']?.number || 0,
  ж–ҮжЎҲзүҲжң¬: p['ж–ҮжЎҲзүҲжң¬']?.number || 1,
} }];

// зҷҪеҗҚе–®жё…жҙ—пјҡеҸӘз•ҷе»Је‘Ҡж¬„дҪҚпјҢеұӢдё»еҖӢиіҮ(seller_*/apograph_*)дёҖеҫӢ drop
const d = $input.first().json.data || $input.first().json;
const num = v => (v === null || v === undefined || v === '') ? null : Number(v);
const s = v => (v === null || v === undefined) ? '' : String(v).trim();
const features = [d.feature_1, d.feature_2, d.feature_3, d.feature_4, d.feature_5].map(s).filter(Boolean);
const ж©ҹиғҪ = { еӯёеҚҖ: s(d.school_info), е•ҶеңҲ: s(d.market_info), жҚ·йҒӢ: s(d.mrt_station), зҒ«и»Ҡ: s(d.train_station), е…¬и»Ҡ: s(d.bus_station) };
// FB дёҖеүҮиІјж–ҮжңҖеӨҡеё¶ 10 ејөпјҢеӨҡзҡ„дёҚиҰҒдёҠеӮіпјҲд№ӢеүҚе…ЁйғЁеӮіе®ҢжүҚдёҹжҺүпјҢзҷҪиҠұ API е‘јеҸ«пјү
const images = (d.images || []).map(x => x.image_url).filter(Boolean).slice(0, 10);
return [{ json: {
  contract_no: s(d.contract_no).toUpperCase(),
  keisId: d.id,
  жЎҲеҗҚ: s(d.case_name),
  зёҪеғ№иҗ¬: num(d.case_price),
  е–®еғ№: num(d.unit_price),
