  е»әзү©еқӘ: (d.total_area == null || d.total_area === '') ? null : Math.round(Number(d.total_area)*10)/10,
  жЁ“еұӨ: s(d.floor_info),
  зӨҫеҚҖ: s(d.community_name),
  ең°еқҖ: [s(d.property_address_city), s(d.property_address_district), s(d.property_address_road)].join(''),
  еұӢйҪЎ: (d.age == null || d.age === '') ? null : Math.round(Number(d.age)),
  и»ҠдҪҚ: [s(d.parking_type), s(d.parking_method)].filter(Boolean).join('/'),
