const price = src['зёҪеғ№иҗ¬'];
let body = String(parsed['зІүе°Ҳдё»й«”'] || '').trim();
if (price) {
  const aiNum = (body.match(/(\d{3,7})\s*иҗ¬/) || [])[1];
  if (aiNum && Number(aiNum) !== Number(price)) body = body.split(aiNum + ' иҗ¬').join(price + ' иҗ¬').split(aiNum + 'иҗ¬').join(price + 'иҗ¬');
}
const зІүе°Ҳfooter = '\n\nрҹ“һ и–ӣе…Ҳз”ҹ 0912877583пјҲеҗҢ LINEпјү\nLINEпјҡhttps://line.me/ti/p/kg1pMk4vX8\n\nвҖ”\nеҮұз’ҝиӘјеі°дёҚеӢ•з”ўжңүйҷҗе…¬еҸё\nз¶“зҙҖжҘӯзү№иЁұеӯ—иҷҹпјҡй«ҳеёӮең°ж”ҝзұҚеӯ—з¬¬11034791100иҷҹ\nиӯүз…§еӯ—иҷҹпјҡпјҲ111пјүзҷ»еӯ—з¬¬417208иҷҹ';
const зӨҫеңҳfooter = '\n\nвҖ”\nеҮұз’ҝиӘјеі°дёҚеӢ•з”ўжңүйҷҗе…¬еҸёпҪңи–ӣе…Ҳз”ҹ 0912877583\nз¶“зҙҖжҘӯзү№иЁұеӯ—иҷҹпјҡй«ҳеёӮең°ж”ҝзұҚеӯ—з¬¬11034791100иҷҹ';
const зІүе°Ҳж–ҮжЎҲ = body + зІүе°Ҳfooter;
const зӨҫеңҳж–ҮжЎҲ = String(parsed['зӨҫеңҳдё»й«”'] || '').trim() + зӨҫеңҳfooter;
return [{ json: { ...src, зІүе°Ҳж–ҮжЎҲ, зӨҫеңҳж–ҮжЎҲ } }];

